const getTranslatedLabels = (stage) => {
  //for summary page
  if(!stage) return "Test"+Math.random()*99;

  if (localStorage.getItem("locale") == "en") {
    // Check if there is an underscore in the displayName
    if (stage.formName) return stage.formName;
    else
      return stage.displayName.includes("_")
        ? stage.displayName.split("_")[1]
        : stage.displayName;
  } else if (stage.translations && stage.translations.length > 0) {
    //debugger;
    let label = stage.translations.filter(
      (tanslation) =>
        tanslation.property == "NAME" &&
        tanslation.locale == localStorage.getItem("locale")
    );
    if (label.length > 0) {
      return label[0].value;
    } else {
      if (stage.formName) return stage.formName;
      else
        return stage.displayName?.includes("_")
          ? stage.displayName.split("_")[1]
          : stage.displayName;
    }
  }
  return <Trans>{stage.displayName}</Trans>;
};

const getTranslatedDataElementLabels = (dataElement) => {
  if (localStorage.getItem("locale") == "en") {
    return dataElement.formName
      ? dataElement.formName
      : dataElement.displayName
      ? dataElement.displayName
      : dataElement.description;
  } else if (dataElement.translations && dataElement.translations.length > 0) {
    let label = dataElement.translations.filter(
      (tanslation) =>
        tanslation.property == "NAME" &&
        tanslation.locale == localStorage.getItem("locale")
    );
    if (label.length > 0) {
      return label[0].value;
    } else {
      return dataElement.formName
        ? dataElement.formName
        : dataElement.displayName
        ? dataElement.displayName
        : dataElement.description;
    }
  }
  return dataElement.formName
    ? dataElement.formName
    : dataElement.displayName
    ? dataElement.displayName
    : dataElement.description;
};
function formatDateToDDMMYYYY(dateString) {
  const dataFormat1 = getDateFormat("dateformat");
  const formattedValue = format(new Date(dateString), dataFormat1);
  // const [year, month, day] = dateString.split("-");
  // return `${day}-${month}-${year}`;
  return formattedValue;
}

const getTranslatedDataAttributeLabels = (itemAttributeID, attrData) => {
  let tranlatedAttr;
  attrData.forEach((arr) => {
    if (arr.trackedEntityAttribute.id == itemAttributeID) {
      tranlatedAttr = arr.trackedEntityAttribute;
    }
  });

  if (localStorage.getItem("locale") == "en") {
    return tranlatedAttr?.formName
      ? tranlatedAttr?.formName
      : tranlatedAttr?.displayName
      ? tranlatedAttr?.displayName
      : tranlatedAttr?.description;
  } else if (
    tranlatedAttr.translations &&
    tranlatedAttr.translations.length > 0
  ) {
    //debugger;
    let label = tranlatedAttr.translations.filter(
      (tanslation) =>
        tanslation.property == "NAME" &&
        tanslation.locale == localStorage.getItem("locale")
    );
    if (label.length > 0) {
      return label[0].value;
    } else {
      return tranlatedAttr.formName
        ? tranlatedAttr.formName
        : tranlatedAttr.displayName
        ? tranlatedAttr.displayName
        : tranlatedAttr.description;
    }
  }
  return tranlatedAttr.formName
    ? tranlatedAttr.formName
    : tranlatedAttr.displayName
    ? tranlatedAttr.displayName
    : tranlatedAttr.description;
  // return item.displayName;
};

