  const FieldWatcher = ({ name }) => {
    const {
      input: { value },
    } = useField(name);

    useEffect(() => {
      let initialValues = activeCaseFormData.data
        ? activeCaseFormData.data.formFormat != null
          ? activeCaseFormData.data.formFormat
          : {}
        : {};
      if (
        initialValues &&
        ((!initialValues[name] && value) ||
          (initialValues[name] && initialValues[name] != value))
      ) {
        if (formDataChangeStatus == null) {
          //setFormDataChange(true)
          formDataChangeStatus = true;
        }
      }
    }, [value, name]);

    return null;
  };

  function getDetails() {
    if (activeCaseDetails && activeCaseDetails.data) {
      setGlobalSpinner(true);
      const programId = metaData.programs[0].id;
      const getURL =
        "trackedEntityInstances/" +
        activeCaseDetails.data.trackedEntityInstance +
        ".json?program=" +
        programId +
        "&fields=*?";
      apiServices
        .getAPI(getURL)
        .then((res) => {
          setGlobalSpinner(false);
          let allEvents = res.data.enrollments[0].events;
          setEventsData(allEvents);
          if (allEvents.length == 0 || allEvents.length < 1) {
            swal({
              title: t("Success"),
              text: t("No records found"),
              icon: "success",
              button: t("Close"),
            }).then((res) => {
              if (res) {
                history.goBack();
                //   history.push('layout/cases')
              }
            });
          }
        })
        .catch((error) => {
          setGlobalSpinner(false);
          swal({
            title: "Error",
            text: t(error),
            icon: "error",
            button: t("Close"),
          });
        });
    }
  }

