  function checkAndGetAdherenceDetails(newValue, eventsData) {
    //multiple adherence handling
    // Logic for lab and radio drodown
    // if(_.find(eventsData.enrollments[0].events,{"programStage":"HNnj45fIS5C"})){
    //   let currentEvent = _.find(eventsData.enrollments[0].events,{"programStage":"HNnj45fIS5C"})

    // }
    const labRows2 = [];
    const radRows2 = [];

    eventsData &&
      eventsData.enrollments &&
      eventsData.enrollments[0].events.forEach((event) => {
        event.dataValues
          .filter(({ dataElement }) => labId.includes(dataElement)) // ✅ Only include valid IDs
          .forEach(({ dataElement, value }) => {
            if (!labRows2.find((row) => row.id === dataElement))
              labRows2.push({
                id: dataElement,
                selectedTest: { label: value, value },
              });
          });
        event.dataValues
          .filter(({ dataElement }) => radId.includes(dataElement)) // ✅ Only include valid IDs
          .forEach(({ dataElement, value }) => {
            if (!radRows2.find((row) => row.id === dataElement))
              radRows2.push({
                id: dataElement,
                selectedTest: { label: value, value },
              });
          });
      });
    const assignedLabIds = labRows2.map((row) => row.id);
    const assignedRadIds = radRows2.map((row) => row.id);

    const pendingLabIds = labId.filter((id) => !assignedLabIds.includes(id));
    const pendingRadIds = radId.filter((id) => !assignedRadIds.includes(id));

    if (
      labRows2.length < 10 &&
      labRows2.length > 0 &&
      pendingLabIds.length > 0
    ) {
      labRows2.push({ id: pendingLabIds[0], selectedTest: null });
    }

    if (
      radRows2.length < 5 &&
      radRows2.length > 0 &&
      pendingRadIds.length > 0
    ) {
      radRows2.push({ id: pendingRadIds[0], selectedTest: null });
    }
    if (labRows2.length > 0) setLabRows(labRows2);
    if (radRows2.length > 0) setRadRows(radRows2);

    let labRowsOffline;
    let radRowsOffline;
    if (!navigator.onLine) {
      //     const getLatestLabRowsOffline = (eventsData) => {
      //   if (!Array.isArray(eventsData) || eventsData.length === 0) return [];

      //   const latestEvent = eventsData.reduce((latest, curr) => {
      //     return new Date(curr.eventDate) > new Date(latest.eventDate) ? curr : latest;
      //   }, eventsData[0]);

      //   // 2. Filter matching labid entries with non-empty values
      //   const filteredLabValues = eventsData.flatMap(event =>(event.dataValues || []).filter(
      //     (dv) => labId.includes(dv.dataElement) && dv.value?.trim() !== ""
      //   )
      //   );

      //   // 3. Construct labRows array just like online
      //   const labRows = filteredLabValues.map((dv) => ({
      //     id: dv.dataElement,
      //     selectedTest: {
      //       label: dv.value,
      //       value: dv.value,
      //     }
      //   }));

      //   return labRows;
      // };
      const getLatestLabRowsOffline = (eventsData) => {
        if (!Array.isArray(eventsData) || eventsData.length === 0) return [];

        const filteredLabValues = eventsData.flatMap((event) =>
          (event.dataValues || []).filter(
            (dv) => labId.includes(dv.dataElement) && dv.value?.trim() !== ""
          )
        );

        const labRows = filteredLabValues.map((dv) => ({
          id: dv.dataElement,
          selectedTest: {
            label: dv.value,
            value: dv.value,
          },
        }));

        // Optional: remove duplicate rows by dataElement ID
        const uniqueLabRows = Array.from(
          new Map(
            labRows.map((row) => [`${row.id}-${row.selectedTest.value}`, row])
          ).values()
        );

        return uniqueLabRows;
      };

      const getLatestRadRowsOffline = (eventsData) => {
        if (!Array.isArray(eventsData) || eventsData.length === 0) return [];

        // 2. Filter matching labid entries with non-empty values
        const filteredRadValues = eventsData.flatMap((event) =>
          (event.dataValues || []).filter(
            (dv) => radId.includes(dv.dataElement) && dv.value?.trim() !== ""
          )
        );

        // 3. Construct labRows array just like online
        const radRows = filteredRadValues.map((dv) => ({
          id: dv.dataElement,
          selectedTest: {
            label: dv.value,
            value: dv.value,
          },
        }));
        const uniqueRadRows = Array.from(
          new Map(
            radRows.map((row) => [`${row.id}-${row.selectedTest.value}`, row]) // composite key: id + value
          ).values()
        );
        return uniqueRadRows;
      };

      const currentStageData = eventsData?.services
        ? [].concat(
            ...eventsData.services.map((service) => service.events || [])
          )
        : [];

      labRowsOffline = getLatestLabRowsOffline(currentStageData);
      radRowsOffline = getLatestRadRowsOffline(currentStageData);
      //  if (labRowsOffline.length < 10 && labRowsOffline.length > 0 &&  pendingLabIds.length > 0) {
      labRowsOffline.push({ id: pendingLabIds[0], selectedTest: null });
      // }

      // if (radRowsOffline.length < 5 && radRowsOffline.length > 0 && pendingRadIds.length > 0) {
      radRowsOffline.push({ id: pendingRadIds[0], selectedTest: null });
      // }
      setLabRows(labRowsOffline);
      setRadRows(radRowsOffline);
      //radRowsOffline = getLatestRadRowsOffline(eventsData);
    }
    try {
      let stageIndex =
        newValue > 0 ? (searchEnabled ? newValue - 2 : newValue - 1) : null;
      if (!navigator.onLine) {
        stageIndex = newValue > 0 ? newValue - 1 : null;
      }
      let isCalendarAttrExist = false;
      if (stageIndex != null) {
        let currentStage = programData.programs[0].programStages[stageIndex];
        //let calendarStage = null
        if (
          currentStage.attributeValues &&
          currentStage.attributeValues.length > 0
        ) {
          currentStage.attributeValues.map((val, i) => {
            if (
              val.attribute.displayName == "showFullCalender" &&
              val.value == "true"
            ) {
              isCalendarAttrExist = true;
              setAdherenceStageId(currentStage.id);
              setRadioValue({});
              let dateMedicineTakenID = null;
              let medicineColorCodeID = null;
              let medicineTakenID = null;
              currentStage.programStageDataElements.map((field) => {
                let fieldname = field.dataElement.description
                  ? field.dataElement.description
                  : field.dataElement.formName
                  ? field.dataElement.formName
                  : field.dataElement.displayName;
                if (
                  fieldname.trim().toLocaleLowerCase() ==
                    "date medicine taken" ||
                  fieldname.trim().toLocaleLowerCase() ==
                    "tb_date medicine taken"
                ) {
                  setDateMedicineTakenId(field.dataElement.id);
                  setMedicineTakenDateBO(field.dataElement);
                  dateMedicineTakenID = field.dataElement.id;
                } else if (
                  fieldname.trim().toLocaleLowerCase() == "medicine taken" ||
                  fieldname.trim().toLocaleLowerCase() == "tb_medicine taken"
                ) {
                  setMedicineTakenId(field.dataElement.id);
                  setMedicineTakenBO(field.dataElement);
                  medicineTakenID = field.dataElement.id;
                  try {
                    if (
                      field.dataElement.optionSet &&
                      field.dataElement.optionSet.options
                    ) {
                      setMedicineTakenoptions(
                        field.dataElement.optionSet.options
                      );
                    }
                  } catch (e) {}
                } else if (
                  fieldname.trim().toLocaleLowerCase() == "colour code"
                ) {
                  setMedicineColorCodeId(field.dataElement.id);
                  medicineColorCodeID = field.dataElement.id;
                }
                if (
                  fieldname.trim() == "Reason for missed dose" ||
                  fieldname.trim() == "TBAdherence_Reason for missed dose"
                ) {
                  //Date of treatment completion
                  setReasonForMissedDoseID(field.dataElement.id);
                  setReasonForMissedDoseBO(field.dataElement);
                }
                if (
                  fieldname.trim() == "TPTAdherence_Remarks" ||
                  fieldname.trim() == "TBAdherence_Remarks"
                ) {
                  //Date of treatment completion
                  setAdherenceRemarkId(field.dataElement.id);
                }
                if (
                  fieldname.trim() ==
                    "TPTAdherence_Date for in-person meeting" ||
                  fieldname.trim() == "TBAdherence_Date of in-person meeting"
                ) {
                  //Date of treatment completion
                  setDateforinpersonmeetingId(field.dataElement.id);
                }
                if (
                  fieldname.trim() == "Misseddose_Action" ||
                  fieldname.trim() == "TBAdherence_Missed dose action"
                ) {
                  //Date of treatment completion
                  setMissedDoseActionId(field.dataElement.id);
                }
              });
              let stageData =
                eventsData &&
                eventsData.enrollments &&
                eventsData.enrollments[0]
                  ? eventsData.enrollments[0].events
                  : _.isEmpty(trackentityInstanceDetails)
                  ? []
                  : trackentityInstanceDetails.enrollments[0].events;
              if (!navigator.onLine) {
                let offlineEvents = [];
                eventsData.services.map((ele) => {
                  ele.events.map((evt) => {
                    offlineEvents.push(evt);
                  });
                });
                stageData = offlineEvents;
              }
              let sortedEvents = _.filter(stageData, {
                programStage: currentStage.id,
              });
              //set tpt regimen data
              if (
                DateoftreatmentinitiatedID &&
                currentStage.id == adherenceTPTStageId &&
                tptIntiationStageId
              ) {
                let tptInitiationStageEvent = stageData.filter(
                  (obj) =>
                    obj.programStage == tptIntiationStageId &&
                    obj.status != "SCHEDULE"
                );
                if (tptInitiationStageEvent.length > 0) {
                  tptInitiationStageEvent = _.sortBy(
                    tptInitiationStageEvent,
                    "created"
                  );
                  let finalEvent =
                    tptInitiationStageEvent[tptInitiationStageEvent.length - 1];
                  let treatmentStartDate = _.find(finalEvent.dataValues, {
                    dataElement: DateoftreatmentinitiatedID,
                  });
                  //let treatmentEndDate = _.find(finalEvent.dataValues,{ dataElement: DateoftreatmentcompletionID });
                  let regimen = _.find(finalEvent.dataValues, {
                    dataElement: tptStartRegimenId,
                  });
                  if (treatmentStartDate) {
                    setcalendarStartDate(treatmentStartDate.value);
                  }
                  if (regimen) {
                    setTptStartRegimen(regimen.value);
                  }
                  setcalendarEndDate(null);
                } else {
                  setcalendarStartDate(null);
                  setTptStartRegimen(null);
                  setcalendarEndDate(null);
                }
              } else if (
                TreatmentstartdateId &&
                currentStage.id == adherenceTBStageId &&
                tbTretmentInitiationStageId
              ) {
                let tbInitiationStageEvent = stageData.filter(
                  (obj) =>
                    obj.programStage == tbTretmentInitiationStageId &&
                    obj.status != "SCHEDULE"
                );
                if (tbInitiationStageEvent.length > 0) {
                  tbInitiationStageEvent = _.sortBy(
                    tbInitiationStageEvent,
                    "created"
                  );
                  let finalEvent =
                    tbInitiationStageEvent[tbInitiationStageEvent.length - 1];
                  let treatmentStartDate = _.find(finalEvent.dataValues, {
                    dataElement: TreatmentstartdateId,
                  });
                  let treatmentEndDate = _.find(finalEvent.dataValues, {
                    dataElement: TreatmentcompletiondateId,
                  });
                  if (treatmentStartDate) {
                    setcalendarStartDate(treatmentStartDate.value);
                  } else {
                    setcalendarStartDate(null);
                  }
                  if (treatmentEndDate) {
                    setcalendarEndDate(treatmentEndDate.value);
                  } else {
                    setcalendarEndDate(null);
                  }
                  setTptStartRegimen(null);
                } else {
                  setcalendarStartDate(null);
                  setTptStartRegimen(null);
                }
              } else {
                setcalendarStartDate(null);
                setcalendarEndDate(null);
                setTptStartRegimen(null);
              }
              if (sortedEvents.length > 0) {
                let finalEvents = _.filter(sortedEvents, {
                  dataValues: [{ dataElement: dateMedicineTakenID }],
                });
                let events = [];
                finalEvents.map((event) => {
                  let mediDateObj = _.filter(event.dataValues, {
                    dataElement: dateMedicineTakenID,
                  });
                  let mediColorCodeObj = _.filter(event.dataValues, {
                    dataElement: medicineColorCodeID,
                  });
                  let mediTakenFieldObj = _.filter(event.dataValues, {
                    dataElement: medicineTakenID,
                  });
                  let reasonForMissedDose = reasonForMissedDoseID
                    ? _.find(event.dataValues, {
                        dataElement: reasonForMissedDoseID,
                      })
                    : "";
                  if (mediDateObj.length > 0 && mediColorCodeObj.length > 0) {
                    let obj = {};
                    obj["start"] = mediDateObj[0].value;
                    obj["end"] = mediDateObj[0].value;
                    obj["allDay"] = true;
                    obj["backgroundColor"] = mediColorCodeObj[0].value;
                    obj["display"] = "background";
                    obj["overlap"] = false;
                    obj["editmode"] = true;
                    obj["medicineTaken"] =
                      mediTakenFieldObj && mediTakenFieldObj[0]
                        ? mediTakenFieldObj[0].value
                        : "";
                    if (reasonForMissedDose && reasonForMissedDoseID) {
                      obj["reasonForMissedDose"] = reasonForMissedDose
                        ? reasonForMissedDose.value
                        : false;
                    }
                    events.push(obj);
                  }
                });
                events = _.uniqBy(events, "start");
                setFullCalendarEvents(events);
              } else {
                setFullCalendarEvents([]);
              }
            }
            if (
              val.attribute.displayName == "InsulinTable" &&
              val.value == "true"
            ) {
              let insulinTableHeader = {};
              let nonInsulinTableHeader = {};
              let newArr = showInsulinTableArr;
              newArr.push(currentStage.id);
              setShowInsulinTableArr(newArr);
              setPrescriptionStageId(currentStage.id);
              currentStage.programStageDataElements.map((de) => {
                if (
                  _.find(de.dataElement.attributeValues, {
                    attribute: { name: "ShowInInsulinTable" },
                  }) &&
                  _.find(de.dataElement.attributeValues, {
                    attribute: { name: "ShowInInsulinTable" },
                  }).value == "true"
                ) {
                  const isDrop = sessionUserBoValue?.userRoles?.find(
                    (role) => role.name === "DROP-HCP"
                  );
                  if (isDrop) {
                    const attributeValues =
                      de?.dataElement?.attributeValues || [];
                    const isDropVariableAttr = attributeValues.find(
                      (attr) => attr.attribute?.displayName === "isDropVariable"
                    );
                    if (isDropVariableAttr && isDropVariableAttr.value === "true") {
                      insulinTableHeader[de.dataElement.id] =
                        de.dataElement.formName === "Please Specify"
                          ? "Other Medications"
                          : de.dataElement.formName;
                    }
                  } else {
                    insulinTableHeader[de.dataElement.id] =
                    de.dataElement.formName === "Please Specify"
                      ? "Other Medications"
                      : de.dataElement.formName;
                  }
                }

                if (
                  _.find(de.dataElement.attributeValues, {
                    attribute: { name: "ShowInNon-InsulinTable" },
                  }) &&
                  _.find(de.dataElement.attributeValues, {
                    attribute: { name: "ShowInNon-InsulinTable" },
                  }).value == "true"
                ) {
                  nonInsulinTableHeader[de.dataElement.id] =
                    de.dataElement.formName;
                }
              });
              const isDrop = sessionUserBoValue?.userRoles?.find(
                (role) => role.name === "DROP-HCP"
              );
              let desiredOrder = [
                "Medication Name",
                "Name of the Insulin",
                "Regime Type",
                "Regimen Type",
                "Type of Insulin",
                // "Other Medications",
                "Any Other Medications",
                // "Frequency",
                "Meal",
                "Before/After Meal",
                // <-- We will insert Frequency here conditionally for CC006
                "Time of Dosage",
                // "Dosage",
                // "Dosage (units/day)",
                // " Dosage (units/day) ",
                // "Dosage (breakfast)",
                // "Dosage (lunch)",
                // "Dosage (dinner)",
                "Total Daily Dosage (Units)",
                "Daily Dosage (Units)",
                "Daily Dosage units",
                "Dosage (units/day)",
                "Course of Days",
                "Duration",
                "Time units",
                "Dosage units",
                ...(!isDrop
                  ? ["Any Additional Shot", "Reason for the Shot"]
                  : []),
                // "Additional Comments",
                "",
              ];
              // Insert new variables only when APP_LOCALE === "CC013"
              if(APP_LOCALE === "CC013"){
                  //"Insulin delivery method"
                  const index = desiredOrder.indexOf("Type of Insulin");
                  if (index !== -1) {
                    // Insert Insulin delivery method AFTER "Type of Insulin"
                    desiredOrder.splice(index + 1, 0, "Insulin Delivery Method");
                  }
              }

              // Insert "Frequency" only when APP_LOCALE === "CC006"
              if (APP_LOCALE === "CC006") {
                const index = desiredOrder.indexOf("Before/After Meal");
                if (index !== -1) {
                  // Insert Frequency AFTER "Before/After Meal"
                  desiredOrder.splice(index + 1, 0, "Frequency");

                  // Insert Route BEFORE "Before/After Meal"
                  desiredOrder.splice(index, 0, "Route");
                }
              }

              let desiredOrderNonInsulin = [
                "Name of Non-Insulin diabetic medication",
                "Name of Non Insulin Diabetic Medication",
                "Any Other Medications",
                "Frequency",
                "Dosage units",
                "Meal",
                "Before/After Meal",
                "Time of Dosage",
                "Dosage",
                " Dosage (units/day) ",
                "Dosage (breakfast)",
                "Dosage (units/day)",
                "Dosage (lunch)",
                "Dosage (dinner)",
                "Course of Days",
                "Additional Comments",
              ];

              // Reorder the headers
              let reorderedInsulinTableHeader = {};
              let reorderedNonInsulinTableHeader = {};
              if (desiredOrder && insulinTableHeader) {
                desiredOrder.forEach((header) => {
                  for (let key in insulinTableHeader) {
                    if (insulinTableHeader[key]?.toLowerCase() === header?.toLowerCase()) {
                      reorderedInsulinTableHeader[key] =
                        insulinTableHeader[key];
                      break;
                    }
                  }
                });
              }

              if (desiredOrderNonInsulin && nonInsulinTableHeader) {
                desiredOrderNonInsulin.forEach((header) => {
                  for (let key in nonInsulinTableHeader) {
                    if (nonInsulinTableHeader[key]?.toLowerCase() === header?.toLowerCase()) {
                      reorderedNonInsulinTableHeader[key] =
                        nonInsulinTableHeader[key];
                      break;
                    }
                  }
                });
              }

              setInsulinHeader(reorderedInsulinTableHeader);
              setNonInsulinHeader(reorderedNonInsulinTableHeader);
              getInsulinTableDetail(
                currentStage.id,
                reorderedInsulinTableHeader,
                reorderedNonInsulinTableHeader,
                eventsData
              );
            }
          });
        }

        // if (currentStage.description!= "History" && currentStage.description?.trim()!= "Management" && currentStage.id?.trim()!= patientProfileStageId) {
        //     if (programData.programs[0].programStages != null && !workFlow) {
        //         if (patientStatus !== "Died") {
        //             // Delay execution by 2 seconds (2000ms)
        //             setTimeout(() => {
        //                 starttoNewService(currentStage);
        //             }, 3000);
        //         }

        //   }
        // }

        if (
          (Configuration.addnewservicepopup &&
            Configuration.addnewservicepopup[currentStage.description]) ||
          !isCalendarAttrExist
        ) {
          let allEvents =
            eventsData && eventsData.enrollments && eventsData.enrollments[0]
              ? eventsData.enrollments[0].events
              : _.isEmpty(trackentityInstanceDetails)
              ? []
              : trackentityInstanceDetails.enrollments[0].events;
          if (!navigator.onLine) {
            let offlineEvents = [];
            eventsData.services.map((ele) => {
              ele.events.map((evt) => {
                offlineEvents.push(evt);
              });
            });
            allEvents = offlineEvents;
          }
          let sortedEvents = allEvents
            ? _.filter(allEvents, { programStage: currentStage.id })
            : [];
          setMultiServicesOfflineData(sortedEvents);
        }
      }
    } catch (e) {}
  }

  function fetchActiveTabs(currentStage, formValues) {
    let Flag = true;
    const values = formValues; //activeCaseFormData.data ? activeCaseFormData.data.formFormat : {}
    let prevStageId = "";
    let workFlowHideFlag = true;
    let submittedEventsList = _.isEmpty(trackentityInstanceDetails)
      ? []
      : trackentityInstanceDetails.enrollments[0].events;
    if (programRules != null && programRulesVariables != null) {
      programRules.map((rules) => {
        const filteredRule = rules.programRuleActions.filter(
          (obj) => obj.programRuleActionType == "HIDEPROGRAMSTAGE"
        );

        if (filteredRule.length > 0) {
          const getStageRule = filteredRule.find(
            (obj) => obj.programStage.id == currentStage.id
          );
          if (getStageRule != undefined) {
            const operators = ["==", "!="];
            const condition = rules.condition;
            const splitConditions = condition.split("&&");

            let val = null;
            let conditionArray = [];
            splitConditions.map((splitCondition) => {
              const variableName = splitCondition.match(/\{(.*?)\}/)[1];
              const parentRaw = programRulesVariables.filter(
                (obj) => obj.displayName == splitCondition.match(/\{(.*?)\}/)[1]
              ); //[0] .dataElement.id
              const parentNameFromFilter =
                parentRaw.length > 0 ? parentRaw[0].displayName : undefined;
              const parentId =
                parentRaw.length > 0
                  ? parentRaw[0].dataElement
                    ? parentRaw[0].dataElement.id
                    : undefined
                  : undefined;

              const parentNameFromFilterStart =
                splitCondition.search(parentNameFromFilter);
              const parentNameLength = parentNameFromFilter
                ? parentNameFromFilter.length
                : undefined;

              const operatorInitLength =
                parentNameFromFilterStart + parentNameLength + 2;

              const operator = splitCondition.substring(
                operatorInitLength,
                operatorInitLength + 2
              );

              const alternateOperatorFinding = operators.map((ops) => {
                if (splitCondition.search(ops) > -1) {
                  const a = {
                    operator: ops,
                    operatorLength: splitCondition.search(ops),
                  };
                  return a;
                }
              });

              const stringLength = splitCondition.length;
              if (parentNameFromFilter) {
                const filteredOperator = alternateOperatorFinding.filter(
                  (obj) => obj != undefined
                );

                const conditionValueRaw =
                  filteredOperator.length > 0
                    ? splitCondition.substring(
                        filteredOperator[0].operatorLength + 3,
                        splitCondition.length
                      )
                    : undefined;

                const removeEmptySpace =
                  conditionValueRaw != undefined
                    ? conditionValueRaw.substring(
                        conditionValueRaw.length - 1,
                        conditionValueRaw.length
                      ) == " "
                      ? conditionValueRaw.substring(
                          0,
                          conditionValueRaw.length - 1
                        )
                      : conditionValueRaw
                    : undefined;

                const conditionValue =
                  removeEmptySpace != undefined
                    ? removeEmptySpace.substring(1, removeEmptySpace.length - 1)
                    : undefined;
                const conditionalOperator =
                  filteredOperator.length > 0
                    ? filteredOperator[0].operator
                    : undefined;
                let conditionForValidation = null;
                if (conditionalOperator != undefined) {
                  val = conditionValue;
                  switch (conditionalOperator) {
                    case "==":
                      if (values != undefined) {
                        if (
                          values[parentId] != undefined &&
                          String(values[parentId]) == String(conditionValue)
                        ) {
                          Flag = false;
                        } else {
                          Flag = true;
                        }
                      }

                      break;
                  }
                }
              }
            });
          }
        }
      });
    }

    if (Flag == true) {
      if (activeTabsOnSubmit[activeTabsOnSubmit.length - 1]) {
        prevStageId = activeTabsOnSubmit[activeTabsOnSubmit.length - 1];
        let filterPrevStageEvents = submittedEventsList.filter(
          (obj) => obj.programStage == prevStageId
        );
        if (filterPrevStageEvents.length > 0) {
          const prevStageLatestData = filterPrevStageEvents[0]; //filterPrevStageEvents[filterPrevStageEvents.length - 1]
          const prevStageLatestDataEventId = prevStageLatestData.event;
          const findIndexOfPrevStageLatestDataEventId =
            submittedEventsList.findIndex(
              (obj) => obj.event == prevStageLatestDataEventId
            );
          const findNextIndexOfIndexOfPrevStageLatestDataEventId =
            submittedEventsList[findIndexOfPrevStageLatestDataEventId + 1];

          if (findNextIndexOfIndexOfPrevStageLatestDataEventId == undefined) {
            workFlowHideFlag = false;
          } else {
            workFlowHideFlag = true;
          }
        } else {
          workFlowHideFlag = false;
        }
      } else {
        workFlowHideFlag = true;
      }

      activeTabsOnSubmit.push(currentStage.id);
    } else {
    }
    return activeTabsOnSubmit;
  }

