  function stageAccessCheck(stages) {
    const userList = stages.userAccesses;
    const userGroups = stages.userGroupAccesses;
    let stageAcsess = false;
    const getUSerBo = userData;
    const userGroupID =
      getUSerBo.userGroups && getUSerBo.userGroups.length > 0
        ? getUSerBo.userGroups[0].id
        : getUSerBo.id;
    const filterUserIdInMeta =
      userList && userList.length > 0
        ? userList.filter((obj) => obj.id == getUSerBo.id)
        : [];
    const filterUserGroupInMeta =
      userGroups && userGroups.length > 0
        ? userGroups.filter((obj) => obj.id == userGroupID)
        : [];
    if (filterUserIdInMeta.length > 0) {
      const filteredUserList = filterUserIdInMeta[0].access;
      if (filteredUserList == "rw------" || filteredUserList == "rwrw----") {
        stageAcsess = true;
      }
    } else if (filterUserGroupInMeta.length > 0) {
      const filteredUserList = filterUserGroupInMeta[0].access;
      if (filteredUserList == "rw------" || filteredUserList == "rwrw----") {
        stageAcsess = true;
      }
    }
    return stageAcsess;
  }

  function getNextAccessibleStage(nextStageId, fetchActiveTab, programData, currentStageId) {
      const currentIndex = activeTabs.indexOf(nextStageId);

      for (let i = currentIndex; i < activeTabs.length; i++) {
        const stageId = activeTabs[i];

        const nextStageObj = programData.programs[0].programStages.find(
          (obj) => obj.id === stageId
        );

        if (nextStageObj && stageAccessCheck(nextStageObj) && (!currentStageId || (currentStageId && nextStageId != currentStageId))) {
          return {
            nextStageId: stageId,
            stepsToMove: i - currentIndex,
            redirectedHome: false
          };
        }
      }

        return {
          nextStageId: null,
          stepsToMove: 0,
          redirectedHome: true
        };
      }

