  function renderRegistrationField(registrationFields, values, form) {
    const onGoogleLocationChangeParent = (value) => {
      values[value.fieldId] = value.value.label;
      if (
        Configuration.registrationForm.googleLocationLatLngFeilds[value.fieldId]
      ) {
        if (
          Configuration.registrationForm.googleLocationLatLngFeilds[
            value.fieldId
          ].lat &&
          Configuration.registrationForm.googleLocationLatLngFeilds[
            value.fieldId
          ].lng
        ) {
          if (value.lat && value.lng) {
            values[
              Configuration.registrationForm.googleLocationLatLngFeilds[
                value.fieldId
              ].lat
            ] = value.lat.toString();
            values[
              Configuration.registrationForm.googleLocationLatLngFeilds[
                value.fieldId
              ].lng
            ] = value.lng.toString();
          }
        }
      }

      const activeCaseFormData = {
        data: {
          formFormat: values, //valueForFormInput,
          dhisFormat: null, //
        },
      };

      OfflineDb.setDataIntoPouchDB("activeCaseFormData", activeCaseFormData);
      setActiveCaseFormData(activeCaseFormData);
    };
    
    return (
      <>
        <CreateField
          formRef={formRef}
          fieldData={registrationFields}
          values={values}
          programRules={programRules}
          programData={programData.programs[0]}
          programRulesVariables={programRulesVariables}
          linkContactFlag={linkContactFlag}
          onGoogleLocationChangeParent={onGoogleLocationChangeParent}
          activeCaseDetails={activeCaseDetails}
          OUJSON={OUJSON}
          Configuration={Configuration}
          customfieldobj={customfieldobj}
          currentGeolocation={currentGeolocation}
          userBO={sessionUserBoValue}
          availableAddressOptions={availableAddressOptions}
          availableContactOptions={availableContactOptions}
          customClassName={
            localStorage.getItem("fontSize")
              ? "FS" + localStorage.getItem("fontSize")
              : ""
          }
          cameraStatus={openCamera}
          cameraClick={() => handleCameraClick(values)}
          cameraClose={() => handleCameraClose(values)}
          imagePath={profileimageDataUrl}
          clearCameraImage={() => removeCameraImage(values)}
          programBoDetails={programBoDetails}
        />
        {/* <FieldWatcher name={registrationFields.trackedEntityAttribute.id} /> */}
      </>
    );
  }

