  function renderStageField(fields, values, form, stages, currentStage) {
    if (!fields) return;

    if (
      (currentStage.id == referralServiceStageId &&
        values[clientTypeID] == Configuration.ltbiLinkVariables.index &&
        fields.dataElement.id != referToFacilityCenter &&
        fields.dataElement.id != selectReferralServiceId) ||
      (currentStage.id == referralServiceStageId &&
        fields.dataElement.id == symptomsID)
    ) {
      return;
    } else if (
      currentStage.id == adherenceTPTStageId &&
      fields.dataElement &&
      (fields.dataElement.id == dateMedicineTakenId ||
        fields.dataElement.id == medicineTakenId ||
        fields.dataElement.id == medicineTakenId ||
        fields.dataElement.id == medicineColorCodeId ||
        fields.dataElement.id == adherenceRemarkId ||
        fields.dataElement.id == missedDoseActionId ||
        fields.dataElement.id == dateforinpersonmeetingId)
    ) {
      return;
    } else if (
      currentStage.id == adherenceTBStageId &&
      fields.dataElement &&
      (fields.dataElement.id == reasonForMissedDoseID ||
        fields.dataElement.id == adherenceRemarkId ||
        fields.dataElement.id == missedDoseActionId ||
        fields.dataElement.id == dateforinpersonmeetingId)
    ) {
      return;
    } else if (
      currentStage.id == tbTretmentInitiationStageId &&
      fields.dataElement &&
      fields.dataElement.description &&
      fields.dataElement.description == "TBAdherence_Interruption action"
    ) {
      return;
    } else if (
      currentStage.id == tptIntiationStageId &&
      fields.dataElement &&
      missedAdherenceActionId &&
      fields.dataElement.id == missedAdherenceActionId
    ) {
      return;
    } else if (currentStage.id == managementStageId) {
      return (
        <>
          <CreateStageFieldManagement
            selectedOption={selectedOption}
            formRef={formRef}
            fieldData={fields}
            values={values}
            programRules={programRules}
            programData={programData.programs[0]}
            programRulesVariables={programRulesVariables}
            dataElementGroup={dataElementGroup}
            stages={stages}
            orgid={userData.organisationUnits[0].id}
            OUJSON={OUJSON}
            customfieldobj={customfieldobj}
            programBoDetails={programBoDetails}
            Configuration={Configuration}
            currentstagename={currentStage.name}
            userBO={sessionUserBoValue}
            customClassName={
              localStorage.getItem("fontSize")
                ? "FS" + localStorage.getItem("fontSize")
                : ""
            }
          />
          {/* <FieldWatcher name={fields.dataElement.id} /> */}
        </>
      );
    } else if (currentStage.id == presciptionStageId) {
      return (
        <>
          <CreateStageField
            formRef={formRef}
            fieldData={fields}
            values={values}
            programRules={programRules}
            programData={programData.programs[0]}
            programRulesVariables={programRulesVariables}
            dataElementGroup={dataElementGroup}
            stages={stages}
            orgid={userData.organisationUnits[0].id}
            OUJSON={OUJSON}
            customfieldobj={customfieldobj}
            programBoDetails={programBoDetails}
            Configuration={Configuration}
            currentstagename={currentStage.name}
            userBO={sessionUserBoValue}
            activeCaseFormData={activeCaseFormData}
            userData={userData}
            activeCaseDetails={activeCaseDetails}
            glucometerFieldMap={glucometerFields}
            currentStage={currentStage}
            customClassName={
              localStorage.getItem("fontSize")
                ? "FS" + localStorage.getItem("fontSize")
                : ""
            }
            trackentityInstanceDetails={trackentityInstanceDetails}
          />
          {/* <FieldWatcher name={fields.dataElement.id} /> */}
        </>
      );
    } else {
      return (
        <>
          <CreateStageField
            formRef={formRef}
            fieldData={fields}
            values={values}
            programRules={programRules}
            programData={programData.programs[0]}
            programRulesVariables={programRulesVariables}
            dataElementGroup={dataElementGroup}
            stages={stages}
            orgid={userData.organisationUnits[0].id}
            OUJSON={OUJSON}
            customfieldobj={customfieldobj}
            programBoDetails={programBoDetails}
            Configuration={Configuration}
            currentstagename={currentStage.name}
            userBO={sessionUserBoValue}
            activeCaseFormData={activeCaseFormData}
            userData={userData}
            activeCaseDetails={activeCaseDetails}
            glucometerFieldMap={glucometerFields}
            currentStage={currentStage}
            customClassName={
              localStorage.getItem("fontSize")
                ? "FS" + localStorage.getItem("fontSize")
                : ""
            }
            trackentityInstanceDetails={trackentityInstanceDetails}
          />
          <FieldWatcher name={fields.dataElement.id} />
        </>
      );
    }
  }

  
