function buildLabPayload(labRows) {
  // Keep only rows with a chosen test; output a compact, consistent shape
  return (labRows ?? [])
    .filter(r => r?.selectedTest?.value)
    .map(r => ({
      id: r.id,
      test: r.selectedTest.value,   // or r.selectedTest.label if you prefer
    }));
}

function buildRadPayload(radRows) {
  // Keep only rows with a chosen test; output a compact, consistent shape
  return (radRows ?? [])
    .filter(r => r?.selectedTest?.value)
    .map(r => ({
      id: r.id,
      test: r.selectedTest.value,   // or r.selectedTest.label if you prefer
    }));
}

const handleSaveTemplate = async () => {
  const formApi = formRef.current;
 // if (!formApi) return;

  const { values } = formApi.getState();   // all current values
  // If you "know the ids", they are your Field `name`s:
  const patientadvice = values[PatientAdvice];
  const prescriptionnotes = values[PrescriptionNotes];
  const conclusion = values[Conclusion];
  const changestatus_ = values[changestatus];
  const patientStatus_ = values[patientStatus];
  const medCount = insulinTable.length; 
  const programId = programData?.programs?.[0]?.id; 
  if (!programId) {
    swal({ title: "Error", text: "Program not found.", icon: "error", button: "OK" });
    return;
  }

  const showInputModal = () => {
    swal({
      title: t("Save Template"),
      text: `${t("You have")} ${medCount} ${t("medications in this template")}.\n${t("Please enter a template name")}:`,
      content: {
        element: "input",
        attributes: {
          placeholder: t("Template Name"),
          type: "text",
          name: "templateName",
        },
      },
      buttons: {
        cancel: {
          text: t("Cancel"),
          visible: true,
        },
        confirm: {
          text: t("Save"),
          closeModal: false, 
        },
      },
    }).then(async (templateName) => { 
      // Cancelled or empty
      if (!templateName || templateName.trim() === "") {
        try { swal.stopLoading(); } catch (_) {}
        swal.close();
        return;
      }

      const trimmedName = templateName.trim();

      
      const exists = Array.isArray(templateList)
        ? templateList.some((tpl) => (tpl.label ?? tpl.name) === trimmedName)
        : false;

      if (exists) {
        await swal({
          text: t("Template with this name already exists"),
          icon: "warning",
          button: t("OK"),
        });
        try { swal.stopLoading(); } catch (_) {}
        swal.close();
        
        showInputModal();
        return;
      }

      // const newTemplate = {
      //   medicationList: medicationList ?? insulinTable, 
      //   name: trimmedName,
      // };
      const newTemplate = {
  medicationList: medicationList,
  name: templateName,
  Lab: buildLabPayload(labRows),  // <-- adds "Lab": []
  Rad: buildRadPayload(radRows),
  PatientAdvice: patientadvice,
  PrescriptionNotes: prescriptionnotes,
  Conclusion: conclusion,
  ChangeStatus: changestatus_,
  PatientStatus: patientStatus_ 
};


      try {
        // Try fetching existing templates
        const response = await apiServices.getAPI(
          `40/dataStore/prescriptionTemplate/${programId}`
        );
        const existingTemplates = Array.isArray(response.data) ? response.data : [];

        // Append & PUT
        existingTemplates.push(newTemplate);
        await apiServices.putAPI(
          `40/dataStore/prescriptionTemplate/${programId}`,
          existingTemplates
        );

        await swal({
          title: t?.("Success") || "Success",
          text: t("Template Created Successfully"),
          icon: "success",
          button: t?.("Ok") || "OK",
        });

        
        settemplateList((prev) => [...prev, { label: trimmedName, name: trimmedName, value: newTemplate.medicationList }]);
        setSelectedVisit({ label: trimmedName, name: trimmedName, value: newTemplate.medicationList });
        setTemplateName(false);
      } catch (error) {
        const statusCode = error?.response?.data?.httpStatusCode ?? error?.response?.status;

        if (statusCode === 404) {
          
          await apiServices.postAPI(
            `40/dataStore/prescriptionTemplate/${programId}`,
            [newTemplate]
          );

          await swal({
            title: t?.("Success") || "Success",
            text: t("Template Created Successfully"),
            icon: "success",
            button: t?.("Ok") || "OK",
          });

          settemplateList((prev) => [...prev, { label: trimmedName, name: trimmedName, value: newTemplate.medicationList }]);
          setSelectedVisit({ label: trimmedName, name: trimmedName, value: newTemplate.medicationList });
          setTemplateName(false);
        } else {
          console.error("Error saving template:", error);
          await swal({
            title: t?.("Error") || "Error",
            text: t("Error saving template"),
            icon: "error",
            button: t?.("Close") || "Close",
          });
        }
      } finally {
        
        try { swal.stopLoading(); } catch (_) {}
        try { swal.close(); } catch (_) {}
      }
    });
  };

  showInputModal();
};


