        //                       <TableCell>{(row[typeOfMedicationRoutineVisits] == "Other") ? row[nameOfAddMedicationRoutineVisits] : (row[typeOfMedicationRoutineVisits] == "Non-Insulin") ? row[nameOfNonInsulinRoutineVisits] : row[nameOfInsulinRoutineVisits]}</TableCell>
        //                       <TableCell>{(row[typeOfMedicationRoutineVisits] == "Other") ? row[frequencyOfAddMedicationRoutineVisits] : (row[typeOfMedicationRoutineVisits] == "Non-Insulin") ? row[frequencyOfNonInsulinRoutineVisits] : row[frequencyRoutineVisits]}</TableCell>
        //                       <TableCell>{(row[typeOfMedicationRoutineVisits] == "Other") ? row[dosageOfAddMedicationRoutineVisits] : (row[typeOfMedicationRoutineVisits] == "Non-Insulin") ? row[dosageOfNonInsulinRoutineVisits] : row[dosageRoutineVisits]}</TableCell>
        //                       <TableCell>{row[typeOfMedicationRoutineVisits] != "Insulin" ? "N/A" : row[courseOfDaysOfRoutineVisits]}</TableCell>
        //                       {/* <TableCell onClick={() => removeFromTable(insulinTableInitialAssessment, row.eventdetails ? row.eventdetails.event : "NA", index) } > {row["action"] ? null : ( <DeleteIcon /> )} </TableCell>
        //                       } </TableRow>
