async function findMatchBeforeSearchCNIC(valuesToSave, currentInstanceId = null) {
  try {
    // Identify CNIC attribute from metadata
    const cnicAttribute = metaData.trackedEntityAttributes.find(
      (attr) =>
        attr.displayName?.toLowerCase().includes("cnic") ||
        attr.id === customfieldobj.nationalIdNumber
    );
    if (!cnicAttribute) {
      console.warn("No CNIC attribute found in metadata");
      return false;
    }

    // Extract CNIC value from the form data
    const cnicValue = valuesToSave.find(
      (item) => item.attribute === customfieldobj.nationalIdNumber
    )?.value;

    if (!cnicValue) {
      return false;
    }

    const orgID = sessionUserBoValue.organisationUnits[0].id;
    const programID = sessionUserBoValue.programs[0];
    const subURL = `trackedEntityInstances/query.json?ou=${orgID}&ouMode=ACCESSIBLE&program=${programID}&attribute=${cnicAttribute.id}:EQ:${cnicValue}&pageSize=50&skipPaging=true`;


    const res = await apiServices.getAPI(subURL);

    if (res?.data?.rows?.length > 0) {
      // Identify column index for instanceId
      const instanceIdIndex = res.data.headers.findIndex(
        (h) => h.name === "instance"
      );

      // Check if any record is NOT the current one
      const duplicateExists = res.data.rows.some((row) => {
        const instanceId = row[instanceIdIndex];
        return instanceId !== currentInstanceId; // ignore same instance
      });

      if (duplicateExists) {
        console.warn("CNIC already exists:", cnicValue);
        return true;
      }
    }

    return false;
  } catch (error) {
    console.error("Error in CNIC uniqueness check:", error);
    return false;
  }
}


