  function onSubmit(values) {
    try {
      setGlobalSpinner(false);
      // Code to encrypt value
      // Object.keys(values).map(value => {
      //   if(encryptIds.includes(value))
      //     values[value] = encryptText(values[value])
      // })
      // return
      // END
      if (
        !navigator.onLine &&
        values[clientTypeID] == Configuration.ltbiLinkVariables.index &&
        addIndex
      ) {
        //setAddIndex(true);
        addindexoffline = true;
      }
      if (window.cordova && profileimageDataUrl) {
        values[profileimageUID] = profileimageDataUrl;
      }
      let registrationFields =
        programData.programs[0].programTrackedEntityAttributes;

      // logic to add username and user role attributes

      let userNameField =
        programData.programs[0].programTrackedEntityAttributes.filter(
          (key) => key.trackedEntityAttribute.description == "userName"
        );
      let userRoleField =
        programData.programs[0].programTrackedEntityAttributes.filter(
          (key) => key.trackedEntityAttribute.description == "userRole"
        );
      let fileAttributeID =
        programData.programs[0].programTrackedEntityAttributes.filter(
          (key) =>
            key.trackedEntityAttribute.valueType == "FILE_RESOURCE" ||
            key.trackedEntityAttribute.valueType == "IMAGE"
        )[0]?.trackedEntityAttribute.id;

      let name = "";
      let role = "";
      let tempUserName;
      let tempUserRole;
      if (userNameField[0]?.trackedEntityAttribute.description == "userName") {
        name = userNameField[0].trackedEntityAttribute.attributeValues?.filter(
          (obj) => {
            if (obj.attribute.name === "userNameFlag" && obj.value == "true")
              return obj;
          }
        );
      }
      let fileAttr = "";
      if (fileAttributeID) {
        fileAttr = {
          attribute: fileAttributeID,
          value: null,
        };
      }
      if (userRoleField[0]?.trackedEntityAttribute.description == "userRole") {
        role = userRoleField[0].trackedEntityAttribute.attributeValues?.filter(
          (obj) => obj.attribute.name === "userRoleFlag" && obj.value == "true"
        );
      }
      tempUserName = name.length
        ? {
            attribute: name.length
              ? userNameField[0].trackedEntityAttribute.id
              : null,
            value: username,
          }
        : null;

      tempUserRole = role.length
        ? {
            attribute: role.length
              ? userRoleField[0].trackedEntityAttribute.id
              : null,
            value: userrolename,
          }
        : null;

      let fieldValueWithAttribute = [];

      tempUserName && fieldValueWithAttribute.push(tempUserName);
      tempUserRole && fieldValueWithAttribute.push(tempUserRole);
      fileAttr && fieldValueWithAttribute.push(fileAttr);
      const data = values;
      if (!navigator.onLine && values[offlineFieldId] == undefined) {
        values[offlineFieldId] = Date.now();
      }
      let promises = [];
      Object.keys(values).map(function (objectKey, index) {
        var obj = {
          attribute: objectKey,
          value: values[objectKey],
        };
        const CurrentValueFilter = registrationFields
          ? registrationFields.find(
              (obj) => obj.trackedEntityAttribute.id == objectKey
            )
          : undefined;
        if (CurrentValueFilter) {
          if (
            CurrentValueFilter &&
            CurrentValueFilter.trackedEntityAttribute &&
            CurrentValueFilter.trackedEntityAttribute.valueType &&
            (CurrentValueFilter.trackedEntityAttribute.valueType == "IMAGE" ||
              CurrentValueFilter.trackedEntityAttribute.valueType ==
                "FILE_RESOURCE")
          ) {
            if (data[objectKey] && _.isObject(data[objectKey])) {
              let imgUrl = data[objectKey][0];
              if (navigator.onLine) {
                setGlobalSpinner(true);
                let formData = new FormData();
                formData.append("file", imgUrl);
                promises.push(
                  apiServices
                    .postAPI("fileResources", formData)
                    .then((res) => {
                      if (res.data) {
                        return {
                          attribute: objectKey,
                          value: res.data.response.fileResource.id,
                        };
                      }
                    })
                    .catch((err) => {
                      return {
                        attribute: objectKey,
                        value: imageValue,
                      };
                    })
                );
              }
            } else {
              fieldValueWithAttribute.push(obj);
            }
          } else {
            fieldValueWithAttribute.push(obj);
          }
        }
      });

      if (promises.length == 0) {
        setGlobalSpinner(false);
        if (linkContactFlag.data) {
          if (linkContactFlag.data.enabled == true) {
            //linkContact function

            linkeRegData(fieldValueWithAttribute, values);
          } else {
            if (activeCaseDetails.data) {
              //update

              updateRegData(
                fieldValueWithAttribute,
                values,
                trackentityInstanceDetails
              );
            } else {
              //save
              saveRegData(fieldValueWithAttribute, values);
            }
          }
        } else {
          if (activeCaseDetails.data) {
            //update

            updateRegData(
              fieldValueWithAttribute,
              values,
              trackentityInstanceDetails
            );
          } else {
            //save
            saveRegData(fieldValueWithAttribute, values);
          }
        }
      } else {
        Promise.all(promises).then((responses) => {
          setGlobalSpinner(false);
          responses.map((imageData) => {
            let existingIndex = fieldValueWithAttribute.findIndex(
              (item) => item.attribute === imageData.attribute
            );
            if (existingIndex !== -1) {
              fieldValueWithAttribute[existingIndex] = imageData;
            } else {
              fieldValueWithAttribute.push(imageData);
            }
          });
          if (linkContactFlag.data) {
            if (linkContactFlag.data.enabled == true) {
              //linkContact function

              linkeRegData(fieldValueWithAttribute, values);
            } else {
              if (activeCaseDetails.data) {
                //update

                updateRegData(
                  fieldValueWithAttribute,
                  values,
                  trackentityInstanceDetails
                );
              } else {
                //save
                saveRegData(fieldValueWithAttribute, values);
              }
            }
          } else {
            if (activeCaseDetails.data) {
              //update
              updateRegData(
                fieldValueWithAttribute,
                values,
                trackentityInstanceDetails
              );
            } else {
              //save
              saveRegData(fieldValueWithAttribute, values);
            }
          }
        });
      }

      //saveRegData(fieldValueWithAttribute, values)
    } catch (e) {
      setGlobalSpinner(false);
    }
  }
