                                        // Handle different date formats
                                        let dateObj;
                                        if (storedDate.includes("/")) {
                                            // Handle format like "23/10/2025 17:11"
                                            const [datePart, timePart] = storedDate.split(" "); // Get "23/10/2025" and "17:11"
                                            const [day, month, year] = datePart.split("/").map(Number);
                                          const [hour = 0, minute = 0] = timePart ? timePart.split(":").map(Number) : [0, 0];
                                          dateObj = new Date(year, month - 1, day, hour, minute);
                                        } 
                                        else if (storedDate.includes("-")) 
                                          {
                                        // Parse year-month-day and no time handling for simplicity
                                        const [year, month, day] = storedDate.split("-").map(Number);
                                        dateObj = new Date(year, month - 1, day);
                                          } 
                                      else {
                                        dateObj = new Date(storedDate);
                                      }

