  function checkIsMedicineTakenOnValidDate(selectInfo, currentStage) {
    if (currentStage.id == adherenceTBStageId) {
      let selectedDate = getDateWithoutTime(new Date(selectInfo.dateStr));
      if (
        calendarStartDate &&
        calendarEndDate &&
        selectedDate >= getDateWithoutTime(new Date(calendarStartDate)) &&
        selectedDate <= getDateWithoutTime(new Date()) &&
        selectedDate <= getDateWithoutTime(new Date(calendarEndDate))
      ) {
        return true;
      } else {
        return false;
      }
    } else {
      let selectedDate = getDateWithoutTime(new Date(selectInfo.dateStr));
      if (calendarStartDate && tptStartRegimen && tptStartRegimen == "3HR") {
        if (
          selectedDate >= getDateWithoutTime(new Date(calendarStartDate)) &&
          selectedDate <=
            getDateWithoutTime(
              new Date(moment(calendarStartDate).add(120 - 1, "days"))
            ) &&
          selectedDate <= getDateWithoutTime(new Date())
        ) {
          return true;
        }
      } else if (
        calendarStartDate &&
        tptStartRegimen &&
        tptStartRegimen == "4R"
      ) {
        if (
          selectedDate >= getDateWithoutTime(new Date(calendarStartDate)) &&
          selectedDate <=
            getDateWithoutTime(
              new Date(moment(calendarStartDate).add(160 - 1, "days"))
            ) &&
          selectedDate <= getDateWithoutTime(new Date())
        ) {
          return true;
        }
      } else if (
        calendarStartDate &&
        tptStartRegimen &&
        tptStartRegimen == "6H"
      ) {
        if (
          selectedDate >= getDateWithoutTime(new Date(calendarStartDate)) &&
          selectedDate <=
            getDateWithoutTime(
              new Date(moment(calendarStartDate).add(239 - 1, "days"))
            ) &&
          selectedDate <= getDateWithoutTime(new Date())
        ) {
          return true;
        }
      } else if (
        calendarStartDate &&
        tptStartRegimen &&
        tptStartRegimen == "3HP"
      ) {
        if (
          selectedDate >= getDateWithoutTime(new Date(calendarStartDate)) &&
          selectedDate <=
            getDateWithoutTime(
              new Date(moment(calendarStartDate).add(120 - 1, "days"))
            ) &&
          selectedDate <= getDateWithoutTime(new Date())
        ) {
          //if (trackentityInstanceDetails.enrollments[0].events.length > 0) {
          if (fullCalendarEvents.length > 0) {
            try {
              // let sortedEvents = _.orderBy(_.filter(
              // trackentityInstanceDetails.enrollments[0].events,
              // { programStage: adherenceStageId }
              // ), ['created'], ['desc']);
              let sortedEvents = _.orderBy(
                fullCalendarEvents,
                ["start"],
                ["desc"]
              );
              if (sortedEvents.length > 0) {
                //let lastMedicineTakenDate = _.find(sortedEvents[0].dataValues,{'dataElement':dateMedicineTakenId})
                let lastMedicineTakenDate = sortedEvents[0]["start"]; //_.find(sortedEvents[0].dataValues,{'dataElement':dateMedicineTakenId})
                let medicineTakenStatus = sortedEvents[0]["medicineTaken"]; //_.find(sortedEvents[0].dataValues,{'dataElement':medicineTakenStatus})
                if (lastMedicineTakenDate && medicineTakenStatus) {
                  let date1 = moment(selectedDate);
                  let date2 = moment(lastMedicineTakenDate);
                  let days = date1.diff(date2, "days");
                  if (days >= 7 && medicineTakenStatus == "Yes") {
                    return true;
                  } else if (days >= 1 && medicineTakenStatus == "No") {
                    return true;
                  }
                }
              } else {
                return true;
              }
            } catch (e) {}
          } else {
            return true;
          }
        }
      } else if (
        calendarStartDate &&
        tptStartRegimen &&
        tptStartRegimen == "1HP"
      ) {
        if (
          selectedDate >= getDateWithoutTime(new Date(calendarStartDate)) &&
          selectedDate <=
            getDateWithoutTime(
              new Date(moment(calendarStartDate).add(40 - 1, "days"))
            ) &&
          selectedDate <= getDateWithoutTime(new Date())
        ) {
          return true;
        }
      } else {
        return false;
      }
    }
  }
  function checkIsMedicineTakenOnSelectedDate(dateSelected) {
    if (
      navigator.onLine &&
      trackentityInstanceDetails &&
      trackentityInstanceDetails.enrollments &&
      trackentityInstanceDetails.enrollments[0] &&
      trackentityInstanceDetails.enrollments[0].events.length > 0
    ) {
      let sortedEvents = _.filter(
        trackentityInstanceDetails.enrollments[0].events,
        { programStage: adherenceStageId }
      );
      if (sortedEvents.length > 0) {
        let finalEvents = _.filter(sortedEvents, {
          dataValues: [
            { dataElement: dateMedicineTakenId, value: dateSelected },
          ],
        });
        return finalEvents.length > 0 ? true : false;
      }
    } else if (!navigator.onLine) {
      //do something here
      OfflineDb.getSingleEntity(
        activeCaseDetails.data.trackedEntityInstance
      ).then((res) => {
        let sortedEvents = _.filter(res.services, {
          events: [{ programStage: adherenceStageId }],
        });
        if (sortedEvents.length > 0) {
          let finalEvents = _.filter(sortedEvents, {
            dataValues: [
              { dataElement: dateMedicineTakenId, value: dateSelected },
            ],
          });
          return finalEvents.length > 0 ? true : false;
        }
      });
    } else {
      return false;
    }
  }

  const getSputumTableDetail = () => {
    let sortedEvents = _.filter(
      trackentityInstanceDetails.enrollments[0].events,
      { programStage: specimenStageId }
    );
    if (sortedEvents.length > 0) {
      let arrTemp = [];
      sortedEvents.map((event) => {
        let sputumTableObj = {};
        sputumTableObj["eventdetails"] = Object.assign({}, event);
        event.dataValues.map((dv) => {
          if (dv.dataElement == dateOfSampleCollection) {
            sputumTableObj[dateOfSampleCollection] = moment(dv.value).format(
              "MM/DD/YYYY"
            );
          } else if (dv.dataElement == specimenid) {
            sputumTableObj[specimenid] = dv.value;
          } else if (dv.dataElement == specimenType) {
            sputumTableObj[specimenType] = dv.value;
          } else if (dv.dataElement == noOfSputumCollected) {
            sputumTableObj[noOfSputumCollected] = dv.value;
          } else if (dv.dataElement == sputumQRCode) {
            sputumTableObj[sputumQRCode] = dv.value;
          }
          sputumTableObj["created"] = dv.created;
        });
        sputumTableObj["action"] = "edit";
        arrTemp.push(sputumTableObj);
      });
      setsputumTable(arrTemp);
    }
  };

 const getInsulinTableDetail = (
  id,
  headerInsulin,
  headerNonInsulin,
  eventsData
) => {
  let currentStageData;
  let currentStage;
  let sortedEvents;
  if (!navigator.onLine) {
    const managementStage = programData.programs[0].programStages.find(
      (stage) => stage?.description?.trim() === "Management"
    );
    currentStage = managementStage;
    const currentStageData = eventsData?.services
      ? [].concat(...eventsData.services.map((service) => service.events || []))
      : [];
    sortedEvents = _.filter(currentStageData, {
      programStage: currentStage.id,
    });
  } else {
    sortedEvents = _.filter(
      trackentityInstanceDetails.enrollments[0].events,
      { programStage: id ? id : presciptionStageId }
    );
  }

  // ✅ Sort latest first (by eventDate → completedDate → created)
  sortedEvents.sort((a, b) => {
    const dateA = new Date(a.eventDate || a.completedDate || a.created);
    const dateB = new Date(b.eventDate || b.completedDate || b.created);
    return dateB - dateA; // latest first
  });
  //debugger
  let insulinArr = [];
  let nonInsulinArr = [];
  let uniqueEvents = [];
  if (sortedEvents.length > 0) {
    sortedEvents.map((event) => {
      let insulinTableObj = {};
      let headers = Object.keys(headerInsulin);
      let matchedData = [];

      // Collect matched data values and their created date
      event.dataValues.forEach((data) => {
        if (headers.includes(data.dataElement) && data.value != "") {
          matchedData.push({
            dataElement: data.dataElement,
            value: data.value,
            created: new Date(data.created),
          });
        }
      });

      matchedData.sort((a, b) => a.created - b.created);

      insulinTableObj = matchedData.reduce((acc, curr) => {
        acc[curr.dataElement] = curr.value;
        return acc;
      }, {});

      const isDuplicate = insulinArr.some((existingObj) => {
        const sortedExistingObj = Object.keys(existingObj)
          .sort()
          .reduce((acc, key) => {
            acc[key] = existingObj[key];
            return acc;
          }, {});

        const sortedNewObj = Object.keys(insulinTableObj)
          .sort()
          .reduce((acc, key) => {
            acc[key] = insulinTableObj[key];
            return acc;
          }, {});

        return (
          JSON.stringify(sortedExistingObj) === JSON.stringify(sortedNewObj)
        );
      });

      if (!isDuplicate && Object.keys(insulinTableObj).length > 0) {
        insulinTableObj["eventdetails"] = event;
        insulinArr.push(insulinTableObj);
      }
      setTimeout(() => {
        setinsulinTable(insulinArr);
      }, 1000);
    });
  }
    if (sortedEvents.length > 0) {
      sortedEvents.map((event) => {
        let nonInsulinTableObj = {};
        let headers = Object.keys(headerNonInsulin);
        let matchedData = [];

        // Collect matched data values and their created date
        event.dataValues.forEach((data) => {
          if (headers.includes(data.dataElement)) {
            matchedData.push({
              dataElement: data.dataElement,
              value: data.value,
              created: new Date(data.created),
            });
          }
        });

        // Sort by created date
        matchedData.sort((a, b) => a.created - b.created);

        // Create the final ordered object with dataElement as key and value as the matched value
        nonInsulinTableObj = matchedData.reduce((acc, curr) => {
          acc[curr.dataElement] = curr.value;
          return acc;
        }, {});

        const isDuplicate = nonInsulinArr.some((existingObj) => {
          // Sort the keys of both objects and compare their stringified versions
          const sortedExistingObj = Object.keys(existingObj)
            .sort()
            .reduce((acc, key) => {
              acc[key] = existingObj[key];
              return acc;
            }, {});

          const sortedNewObj = Object.keys(nonInsulinTableObj)
            .sort()
            .reduce((acc, key) => {
              acc[key] = nonInsulinTableObj[key];
              return acc;
            }, {});

          // Compare the sorted objects
          return (
            JSON.stringify(sortedExistingObj) === JSON.stringify(sortedNewObj)
          );
        });

        // const isDuplicate = nonInsulinArr.some(existingObj => {
        //   return JSON.stringify(existingObj) === JSON.stringify(nonInsulinTableObj);
        // });

        // Only push the object if it's not a duplicate
        if (!isDuplicate && Object.keys(nonInsulinTableObj).length > 0) {
          nonInsulinTableObj["eventdetails"] = event;
          nonInsulinArr.push(nonInsulinTableObj);
        }
      });

      setTimeout(() => {
        setNonInsulinTable(nonInsulinArr);
      }, 1000);
    }

    return insulinTable;
};

