function findOptionForTest(opts, testString) {
  if (!testString) return null;
  const exact = (opts || []).find(o => o?.label === testString || o?.value === testString);
  if (exact) return exact;
  const norm = s => String(s || "").trim().toLowerCase();
  return (opts || []).find(
    o => norm(o?.label) === norm(testString) || norm(o?.value) === norm(testString)
  ) || null;
}

// --- LAB ---
function hydrateLabFromTemplate(template,values) {
  const labFromServer = Array.isArray(template?.Lab) ? template.Lab : [];
  setLabRows(prevRows => {
    const byId = new Map((prevRows || []).map(r => [r.id, r]));
     const next = labFromServer.map((saved, idx) => {
      const existing = byId.get(saved.id) || (prevRows?.[idx] ?? { id: saved.id, selectedTest: null });
      const opts = (typeof getAvailableOptions === "function" ? getAvailableOptions(idx) : []) || [];
      let option = findOptionForTest(opts, saved.test);
      if (!option && saved?.test) option = { label: saved.test, value: saved.test }; // optional inject
       if (option) {
        values[saved.id] = option.label;
      }
      return { ...existing, id: saved.id, selectedTest: option };
    });
    // const usedIds = prevRows.map((row) => row.id);
    //     const availableId = labId.find((id) => !usedIds.includes(id)); // Next available ID

    //     next.push({
    //       id: availableId || `custom-${prevRows.length}`,
    //       selectedTest: null,
    //     });
    // // next.push({ id: `lab-empty-${Date.now()}`, selectedTest: null });
    const usedIds = prevRows.map((row) => row.id);
    const availableId = labId.find((id) => !usedIds.includes(id));

    next.push({
      id: availableId || `custom-${prevRows.length}`,
      selectedTest: null,
    });

    return next;
  });
   const activeCaseFormData = {
      data: {
        formFormat: values,
        dhisFormat: null,
      },
    };
    let tempobj = _.cloneDeep(activeCaseFormData);
    setActiveCaseFormData(tempobj);
}

