  const removeFromTable = (array, eventId, index, table) => {
    let trackentityInstanceDetailsMeta = _.cloneDeep(
      trackentityInstanceDetails
    );
    let temparr = _.cloneDeep(array);
    let deleteApi = "events/" + eventId;
    swal({
      title: t("Remove Medication"),
      text: t("Do you want to remove the medication from the prescription?"),
      icon: "info",
      buttons: [t("No"), t("Yes")],
    }).then((willDelete) => {
      if (willDelete) {
        setRemoveMed(true)
        if (_.find(temparr, { eventdetails: { event: eventId } })) {
          // if (_.find(temparr, { eventid:eventId })) {
          apiServices.deleteFromDataStoreAPI(deleteApi);
          const index1 = temparr.findIndex(
            (event) => event?.eventdetails?.event === eventId
          );
          temparr.splice(index1, 1);
          if (table == "insulin") {
            setinsulinTable(temparr);
          } else {
            setNonInsulinTable(temparr);
          }
          let index = _.findIndex(
            trackentityInstanceDetailsMeta.enrollments[0].events,
            { event: eventId }
          );
          trackentityInstanceDetailsMeta.enrollments[0].events.splice(index, 1);
          setTrackentityInstanceDetails(trackentityInstanceDetailsMeta);
        } else {
          temparr.splice(index, 1);
          table === "insulin"
            ? setinsulinTable(temparr)
            : setNonInsulinTable(temparr);
        }
      }
    });
  };

